// ==UserScript==
// @name         Unit Production/Wachtrij
// @version      2.0.0
// @description  True real-time troop queue (correct dynamic calculation)
// @include      https://*.grepolis.com/game/*
// @grant        none
// @author       The Invincble
// ==/UserScript==
/*
    Credits
    -------
    Original concept by Egelman (Wachtrij script)
*/

(async function () {

    const sleep = (n) => new Promise(res => setTimeout(res, n));
    await sleep(1500);

    // =========================
    // 🔥 YOUR ICON HERE
    // =========================
    const QUEUE_ICON = "data:image/png;base64,";
    const HUB_ICON = "";
   // =========================
    // HUB CORE (from your HUB script) :contentReference[oaicite:0]{index=0}
    // =========================
    if (!window.GrepoMenu) {

        (function () {

            const items = [];
            let menuOpen = false;

            window.GrepoMenu = {
                register(item) {
                    items.push(item);
                    renderMenu();
                }
            };

            function createMainButton() {

                const container = document.getElementsByClassName('gods_area_buttons')[0];
                if (!container) return;

                if (document.getElementById('grepo_hub_btn')) return;

                const btn = document.createElement("div");
                 btn.id = "grepo_hub_btn";
                btn.className = "circle_button";
                btn.style.marginTop = "55px";
                btn.style.marginRight = "100%";
                btn.style.position = "relative";
                btn.title = "Script Hub";

                btn.innerHTML = `
                    <img src="${HUB_ICON}"
                        style="
                            width:26px;
                            height:26px;
                            position:absolute;
                            top:50%;
                            left:50%;
                            transform:translate(-50%, -50%);
                            pointer-events:none;

                        ">
                `;

                btn.onclick = () => {
                    menuOpen = !menuOpen;
                    const menu = document.getElementById('grepo_hub_menu');
                    if (menu) menu.style.display = menuOpen ? 'block' : 'none';
                };

                container.appendChild(btn);
            }

            function renderMenu() {

                let menu = document.getElementById('grepo_hub_menu');

                if (!menu) {
                    menu = document.createElement("div");
                    menu.id = "grepo_hub_menu";

                    menu.style.position = "absolute";
                    menu.style.top = "150px";
                    menu.style.background = "#2b1a0f";
                    menu.style.border = "2px solid #8b5a2b";
                    menu.style.borderRadius = "8px";
                    menu.style.padding = "6px";
                    menu.style.display = "none";
                    menu.style.zIndex = "9999";

                    document.body.appendChild(menu);
                }

                menu.innerHTML = items.map(i => `
                    <div class="hub_item" style="
                        display:flex;
                        align-items:center;
                        gap:8px;
                        padding:6px;
                        cursor:pointer;
                    ">
                        <div style="
                            width:22px;
                            height:22px;
                            background:url('${i.icon}') no-repeat center;
                            background-size:contain;
                        "></div>
                        <span style="color:#fff;">${i.name}</span>
                    </div>
                `).join('');

                menu.querySelectorAll('.hub_item').forEach((el, index) => {
                    el.onclick = () => {
                        items[index].action();
                        menu.style.display = 'none';
                        menuOpen = false;
                    };
                });
            }

            const i = setInterval(() => {
                if (document.getElementsByClassName('gods_area_buttons')[0]) {
                    clearInterval(i);
                    createMainButton();
                }
            }, 500);

        })();
    }

    let lastSnapshot = "";

    // =========================
    // CALCULATION (same as both scripts)
    // =========================
    function calculateRemaining(order) {

        const now = Math.floor(Date.now() / 1000);
        const a = order.attributes;

        if (now < a.created_at) return a.count;
        if (now >= a.to_be_completed_at) return 0;

        const duration = a.to_be_completed_at - a.created_at;
        const timePerUnit = duration / a.count;
        const elapsed = now - a.created_at;
        const completed = Math.floor(elapsed / timePerUnit);

        return Math.max(a.count - completed, 0);
    }

    // =========================
    // 🔥 GROUPED UI (from your old script) :contentReference[oaicite:1]{index=1}
    // =========================
    function get_units() {

        const models = MM.getModels()?.UnitOrder;
        if (!models) return "Loading...";

        const units = {};

        Object.values(models).forEach(order => {

            const remaining = calculateRemaining(order);

            if (remaining > 0) {
                const unitId = order.getUnitId();
                units[unitId] = (units[unitId] || 0) + remaining;
            }
        });

        const LAND = ["sword","slinger","archer","hoplite","rider","chariot","catapult"];
        const NAVAL = ["big_transporter","small_transporter","bireme","attack_ship","demolition_ship","trireme","colonize_ship"];
        const MYTH = ["minotaur","manticore","medusa","harpy","cyclops","centaur","pegasus","hydra","cerberus","fury","griffin","satyr","spartoi","ladon","calydonian_boar","godsent","siren"];

        function renderGroup(title, list) {

            const present = list.filter(u => units[u]);
            if (!present.length) return "";

            const items = present.map(u => `
                <div style="display:flex; align-items:center; gap:6px;">
                    <div class="unit_icon40x40 unit ${u}"></div>
                    <span style="font-weight:bold;">${units[u]}</span>
                </div>
            `).join("");

            return `
                <div style="margin-bottom:26px;">
                    <div style="
                        font-family: Georgia, serif;
                        font-size:16px;
                        font-weight:bold;
                        color:#5a3b12;
                        margin-bottom:12px;
                        border-bottom:1px solid rgba(90,59,18,0.35);
                    ">
                        ${title}
                    </div>
                    <div style="
                        display:grid;
                        grid-template-columns: repeat(3, 1fr);
                        gap:14px 24px;
                    ">
                        ${items}
                    </div>
                </div>
            `;
        }

        return `
            ${renderGroup("Land Units", LAND)}
            ${renderGroup("Naval Units", NAVAL)}
            ${renderGroup("Mythical Units", MYTH)}
        `;
    }

    function update_live_content() {
        const container = document.getElementById("wachtrijContent");
        if (!container) return;

        const newContent = get_units();

        if (newContent !== lastSnapshot) {
            container.innerHTML = newContent;
            lastSnapshot = newContent;
        }
    }

    function create_window() {

    const TITLE = "Unit Production";

    // 🔍 Get ALL dialog windows
    const openWindows = GPWindowMgr.getByType(GPWindowMgr.TYPE_DIALOG) || [];

    let existingWindow = null;

    // ✅ Find YOUR window only
    for (let w of openWindows) {
        if (w.getTitle && w.getTitle() === TITLE) {
            existingWindow = w;
            break;
        }
    }

    // ✅ If already open → focus it
    if (existingWindow) {
        existingWindow.toFront();
        return;
    }

    // ✅ Create new window
    GPWindowMgr.Create(GPWindowMgr.TYPE_DIALOG, TITLE);

    // 🔥 IMPORTANT: get the LAST created window (not first!)
    const windowsAfter = GPWindowMgr.getByType(GPWindowMgr.TYPE_DIALOG);
    const w = windowsAfter[windowsAfter.length - 1];

    if (!w) return;

    w.setSize(420, 600);

    const content = get_units();
    lastSnapshot = content;

    w.setContent2(`
        <div style="padding:20px 24px;">
            <div id="wachtrijContent">${content}</div>
        </div>
    `);

    setTimeout(() => {
        w.setPosition(["center", 60]);
    }, 50);
}

    // =========================
    // REGISTER IN HUB
    // =========================
    const waitForMenu = setInterval(() => {
        if (window.GrepoMenu) {
            clearInterval(waitForMenu);

            if (!window.__registeredScripts) window.__registeredScripts = {};

            if (!window.__registeredScripts["wachtrij"]) {
                window.__registeredScripts["wachtrij"] = true;

                window.GrepoMenu.register({
                    name: "Unit Production",
                    icon: QUEUE_ICON,
                    action: create_window
                });
            }
        }
    }, 300);

    setInterval(update_live_content, 60000);

})();
